import pandas as pd
import numpy as np
import itertools

def task_func(data_list=[]):
    if not data_list:
        return pd.DataFrame()

    df = pd.DataFrame(columns=['Position'] + [f'Mean Value_{i}' for i in range(len(data_list[0]))])

    positions = list(itertools.product(*map(range, data_list)))
    position_to_values = {pos: [] for pos in positions}

    for item in data_list:
        for pos, value in zip(positions, item):
            if isinstance(value, (int, float)):
                position_to_values[pos].append(value)

    for pos, values in position_to_values.items():
        mean = np.mean(values) if len(values) > 0 else np.nan
        df.loc[len(df.index), 'Position'] = pos
        df.loc[len(df.index), f'Mean Value_{pos[1]}'] = mean

    return df
